package com.xoxo.pos.tables;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/tables") public class BarTableController{private final BarTableRepository repo;public BarTableController(BarTableRepository repo){this.repo=repo;}@GetMapping public List<BarTable> list(){return repo.findByActiveTrueOrderByIdAsc();}@GetMapping("/all") public List<BarTable> all(){return repo.findAll();}@PostMapping public BarTable create(@RequestBody BarTable t){return repo.save(t);}@PutMapping("/{id}") public BarTable update(@PathVariable Long id,@RequestBody BarTable r){var t=repo.findById(id).orElseThrow();t.setName(r.getName());t.setActive(r.isActive());return repo.save(t);}@PatchMapping("/{id}/toggle") public BarTable toggle(@PathVariable Long id){var t=repo.findById(id).orElseThrow();t.setActive(!t.isActive());return repo.save(t);}}
